#include <iostream>
using namespace std;
int main()
{
    int a,b,c,f=0,s=0;
    cin>>a>>b>>c;
    if(a>b)
    {
        f=b;
        b=a;
        a=f;
    }
    if(b>c)
    {
        f=c;
        c=b;
        b=f;
    }
    if(a>b)
    {
        f=b;
        b=a;
        a=f;
    }
    s=a*a+b*b;
    if((a+b<=c)||(a+c<=b)||(c+b<=a))
    {
        cout<<"Not triangle";
    }
    else if((a+b>c)&&(a+c>b)&&(c+b>a))
    {
        if(s>c*c)
        {
            cout<<"Acute triangle"<<endl;
        }
        if(s==c*c)
        {
            cout<<"Right triangle"<<endl;
        }
        if(s<c*c)
        {
            cout<<"Obtuse triangle"<<endl;
        }
        if((a==b)||(b==c)||(a==c))
        {
            cout<<"Isosceles triangle"<<endl;
        }
        if((a==b)&&(b==c)&&(a==c))
        {
            cout<<"Equilateral triangle";
        }
    }
    return 0;
}
